import{_ as t,c as i,o as a,a0 as o}from"./chunks/framework.d22c6mgx.js";const p=JSON.parse('{"title":"Home Assistant MCP Integration","description":"","frontmatter":{},"headers":[],"relativePath":"mcp/ha.md","filePath":"mcp/ha.md"}'),n={name:"mcp/ha.md"};function s(r,e,l,c,h,u){return a(),i("div",null,e[0]||(e[0]=[o(`<h1 id="home-assistant-mcp-integration" tabindex="-1">Home Assistant MCP Integration <a class="header-anchor" href="#home-assistant-mcp-integration" aria-label="Permalink to &quot;Home Assistant MCP Integration&quot;">​</a></h1><p>To improve architectural flexibility and stability, py-xiaozhi has removed the built-in Home Assistant (HA). You can now connect to HA via the WSS-based Home Assistant MCP external plugin, which connects directly to the XiaoZhi AI server through the MCP protocol without any intermediate relay. This plugin is open-sourced and maintained by c1pher-cn, with full support for device status queries, entity control, and automation management.</p><p>Project Repository: <a href="https://github.com/c1pher-cn/ha-mcp-for-xiaozhi" target="_blank" rel="noreferrer">ha-mcp-for-xiaozhi</a></p><h2 id="plugin-features" tabindex="-1">Plugin Features <a class="header-anchor" href="#plugin-features" aria-label="Permalink to &quot;Plugin Features&quot;">​</a></h2><h3 id="core-capabilities" tabindex="-1">Core Capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core Capabilities&quot;">​</a></h3><ol><li><strong>Direct Connection to XiaoZhi Server</strong>: Home Assistant acts as an MCP server, connecting directly to the XiaoZhi server via the WebSocket protocol without any relay</li><li><strong>Multi-API Group Proxy</strong>: Select multiple API groups in a single entity (Home Assistant built-in control API, user-defined MCP Servers)</li><li><strong>Multi-Entity Support</strong>: Supports configuring multiple entity instances simultaneously</li><li><strong>HACS Integration</strong>: One-click installation via the HACS store for easy management and updates</li></ol><h3 id="technical-advantages" tabindex="-1">Technical Advantages <a class="header-anchor" href="#technical-advantages" aria-label="Permalink to &quot;Technical Advantages&quot;">​</a></h3><ul><li><strong>Low Latency</strong>: Direct connection architecture reduces network relay latency</li><li><strong>High Reliability</strong>: WebSocket persistent connection for better stability</li><li><strong>Easy Scalability</strong>: Supports proxying other MCP Servers, strong extensibility</li><li><strong>Easy Maintenance</strong>: HACS management with automatic updates</li></ul><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><p><strong>Device Status Queries:</strong></p><ul><li>&quot;What is the current state of the living room light&quot;</li><li>&quot;Check the status of all lights&quot;</li><li>&quot;What does the temperature sensor show&quot;</li><li>&quot;Is the air conditioner on right now&quot;</li></ul><p><strong>Device Control:</strong></p><ul><li>&quot;Turn on the living room light&quot;</li><li>&quot;Turn off all lights&quot;</li><li>&quot;Set the air conditioner temperature to 25 degrees&quot;</li><li>&quot;Adjust the living room light brightness to 80%&quot;</li></ul><p><strong>Scene Control:</strong></p><ul><li>&quot;Activate sleep mode&quot;</li><li>&quot;Activate the coming home scene&quot;</li><li>&quot;Execute the goodnight scene&quot;</li><li>&quot;Start party mode&quot;</li></ul><p><strong>Advanced Control:</strong></p><ul><li>&quot;Control the TV via script&quot;</li><li>&quot;Execute custom automation&quot;</li><li>&quot;Control multimedia devices&quot;</li><li>&quot;Manage security system&quot;</li></ul><h2 id="installation-guide" tabindex="-1">Installation Guide <a class="header-anchor" href="#installation-guide" aria-label="Permalink to &quot;Installation Guide&quot;">​</a></h2><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ul><li>Home Assistant installed and running</li><li>HACS (Home Assistant Community Store) installed</li><li>XiaoZhi AI account and MCP endpoint address</li></ul><h3 id="installation-steps" tabindex="-1">Installation Steps <a class="header-anchor" href="#installation-steps" aria-label="Permalink to &quot;Installation Steps&quot;">​</a></h3><h4 id="_1-install-via-hacs" tabindex="-1">1. Install via HACS <a class="header-anchor" href="#_1-install-via-hacs" aria-label="Permalink to &quot;1. Install via HACS&quot;">​</a></h4><ol><li>Open HACS and search for <code>xiaozhi</code> or <code>ha-mcp-for-xiaozhi</code></li></ol><img width="700" alt="HACS Search Interface" src="https://github.com/user-attachments/assets/fa49ee7c-b503-49fa-ad63-512499fa3885"><ol start="2"><li>Click download and install the plugin</li></ol><img width="500" alt="Plugin Download Interface" src="https://github.com/user-attachments/assets/1ee75d6f-e1b0-4073-a2c7-ee0d72d002ca"><ol start="3"><li>Restart Home Assistant</li></ol><h4 id="_2-manual-installation" tabindex="-1">2. Manual Installation <a class="header-anchor" href="#_2-manual-installation" aria-label="Permalink to &quot;2. Manual Installation&quot;">​</a></h4><p>If installation via HACS is not possible, you can download manually:</p><ol><li>Download the latest version from <a href="https://github.com/c1pher-cn/ha-mcp-for-xiaozhi/releases" target="_blank" rel="noreferrer">GitHub Releases</a></li><li>Extract to the <code>custom_components</code> directory</li><li>Restart Home Assistant</li></ol><h3 id="configuration-steps" tabindex="-1">Configuration Steps <a class="header-anchor" href="#configuration-steps" aria-label="Permalink to &quot;Configuration Steps&quot;">​</a></h3><h4 id="_1-add-integration" tabindex="-1">1. Add Integration <a class="header-anchor" href="#_1-add-integration" aria-label="Permalink to &quot;1. Add Integration&quot;">​</a></h4><ol><li>Go to <strong>Settings &gt; Devices &amp; Services &gt; Add Integration</strong></li><li>Search for &quot;Mcp&quot; or &quot;MCP Server for Xiaozhi&quot;</li></ol><img width="600" alt="Add Integration Interface" src="https://github.com/user-attachments/assets/07a70fe1-8c6e-4679-84df-1ea05114b271"><ol start="3"><li>Select and click add</li></ol><h4 id="_2-configure-parameters" tabindex="-1">2. Configure Parameters <a class="header-anchor" href="#_2-configure-parameters" aria-label="Permalink to &quot;2. Configure Parameters&quot;">​</a></h4><p>The configuration screen requires the following information:</p><p><strong>Basic Configuration:</strong></p><ul><li><strong>XiaoZhi MCP Endpoint Address</strong>: The MCP endpoint address obtained from the XiaoZhi AI dashboard</li><li><strong>Device Name</strong>: Set an identifying name for this Home Assistant instance</li></ul><p><strong>API Group Selection:</strong></p><ul><li><strong>Assist</strong>: Home Assistant built-in control functions</li><li><strong>Other MCP Servers</strong>: If you have configured other MCP servers in Home Assistant, you can choose to proxy them to XiaoZhi as well</li></ul><img width="600" alt="Configuration Interface" src="https://github.com/user-attachments/assets/38e98fde-8a6c-4434-932c-840c25dc6e28"><h4 id="_3-entity-exposure-settings" tabindex="-1">3. Entity Exposure Settings <a class="header-anchor" href="#_3-entity-exposure-settings" aria-label="Permalink to &quot;3. Entity Exposure Settings&quot;">​</a></h4><p>To allow XiaoZhi to control devices, you need to expose the corresponding entities:</p><ol><li>Go to <strong>Settings &gt; Voice Assistants &gt; Expose</strong></li><li>Select the devices and entities you want XiaoZhi to control</li><li>Save the settings</li></ol><h4 id="_4-verify-connection" tabindex="-1">4. Verify Connection <a class="header-anchor" href="#_4-verify-connection" aria-label="Permalink to &quot;4. Verify Connection&quot;">​</a></h4><ol><li>Wait about 1 minute after configuration is complete</li><li>Log in to the XiaoZhi AI dashboard and go to the MCP endpoint page</li><li>Click refresh and check if the connection status is normal</li></ol><img width="600" alt="Connection Status Check" src="https://github.com/user-attachments/assets/ace79a44-6197-4e94-8c49-ab9048ed4502"><h2 id="usage-examples" tabindex="-1">Usage Examples <a class="header-anchor" href="#usage-examples" aria-label="Permalink to &quot;Usage Examples&quot;">​</a></h2><h3 id="basic-device-control" tabindex="-1">Basic Device Control <a class="header-anchor" href="#basic-device-control" aria-label="Permalink to &quot;Basic Device Control&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Turn on the living room light&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;OK, the living room light has been turned on for you&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: &quot;Set the air conditioner temperature to 26 degrees&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;The air conditioner temperature has been set to 26 degrees&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: &quot;Turn off all lights&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;All lights have been turned off for you&quot;</span></span></code></pre></div><h3 id="status-queries" tabindex="-1">Status Queries <a class="header-anchor" href="#status-queries" aria-label="Permalink to &quot;Status Queries&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: &quot;What is the current temperature in the living room&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;The living room temperature sensor shows the current temperature is 23.5 degrees&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: &quot;Which lights are currently on&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;The lights currently on are: living room light, bedroom bedside lamp&quot;</span></span></code></pre></div><h3 id="scene-control" tabindex="-1">Scene Control <a class="header-anchor" href="#scene-control" aria-label="Permalink to &quot;Scene Control&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User: &quot;Execute sleep mode&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;Sleep mode scene has been executed for you. All lights are off and curtains are drawn&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>User: &quot;Activate the coming home scene&quot;</span></span>
<span class="line"><span>XiaoZhi: &quot;Welcome home! The living room light and hallway light have been turned on for you, and the air conditioner has been set to a comfortable temperature&quot;</span></span></code></pre></div><h2 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-label="Permalink to &quot;Debugging&quot;">​</a></h2><h3 id="_1-entity-exposure-check" tabindex="-1">1. Entity Exposure Check <a class="header-anchor" href="#_1-entity-exposure-check" aria-label="Permalink to &quot;1. Entity Exposure Check&quot;">​</a></h3><p>The number of exposed tools depends on the types of entities you expose to the Home Assistant voice assistant:</p><ul><li>Go to <strong>Settings &gt; Voice Assistants &gt; Expose</strong></li><li>Ensure the devices you need to control have been added to the exposed list</li></ul><h3 id="_2-version-requirements" tabindex="-1">2. Version Requirements <a class="header-anchor" href="#_2-version-requirements" aria-label="Permalink to &quot;2. Version Requirements&quot;">​</a></h3><p>It is recommended to use the latest version of Home Assistant:</p><ul><li>Newer versions provide more complete tools and APIs</li><li>The May version shows significant improvements in tool support compared to the March version</li></ul><h3 id="_3-debugging-methods" tabindex="-1">3. Debugging Methods <a class="header-anchor" href="#_3-debugging-methods" aria-label="Permalink to &quot;3. Debugging Methods&quot;">​</a></h3><p>When the control results do not meet expectations:</p><p><strong>Check XiaoZhi Chat History:</strong></p><ol><li>Check how XiaoZhi understands and processes instructions</li><li>Confirm whether the Home Assistant tool was called</li><li>Analyze whether the call parameters are correct</li></ol><p><strong>Known Issues:</strong></p><ul><li>Light control may conflict with built-in screen control</li><li>Music control may conflict with built-in music functions</li><li>These issues will be resolved after the XiaoZhi server supports built-in tool selection next month</li></ul><h3 id="_4-debug-logs" tabindex="-1">4. Debug Logs <a class="header-anchor" href="#_4-debug-logs" aria-label="Permalink to &quot;4. Debug Logs&quot;">​</a></h3><p>If the Home Assistant function call is correct but execution is abnormal:</p><ol><li>Enable debug logging for this plugin in Home Assistant</li><li>Reproduce the problematic operation</li><li>Check the detailed execution status in the logs</li></ol><h2 id="demo-videos" tabindex="-1">Demo Videos <a class="header-anchor" href="#demo-videos" aria-label="Permalink to &quot;Demo Videos&quot;">​</a></h2><p>To better understand the plugin&#39;s features, you can watch the following demo videos:</p><ul><li><a href="https://www.bilibili.com/video/BV1XdjJzeEwe" target="_blank" rel="noreferrer">Integration Demo Video</a> - Basic installation and configuration process</li><li><a href="https://www.bilibili.com/video/BV18DM8zuEYV" target="_blank" rel="noreferrer">TV Control Demo</a> - TV control via custom script</li><li><a href="https://www.bilibili.com/video/BV1SruXzqEW5" target="_blank" rel="noreferrer">Advanced Tutorial</a> - Detailed tutorial on Home Assistant, LLM, MCP, and XiaoZhi</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h3><p><strong>1. Connection Failed</strong></p><ul><li>Check if the XiaoZhi MCP endpoint address is correct</li><li>Confirm Home Assistant network connection is normal</li><li>Check firewall settings</li></ul><p><strong>2. Device Cannot Be Controlled</strong></p><ul><li>Confirm the device has been exposed in the voice assistant</li><li>Check if the device entity status is normal</li><li>Verify if the device supports the corresponding operation</li></ul><p><strong>3. Partial Function Conflicts</strong></p><ul><li>Temporarily disable built-in functions</li><li>Adjust device naming to avoid conflicts</li><li>Wait for the XiaoZhi server tool selection feature update</li></ul><p><strong>4. Response Delay</strong></p><ul><li>Check network connection quality</li><li>Optimize Home Assistant performance</li><li>Reduce unnecessary entity exposure</li></ul><h3 id="debugging-tips" tabindex="-1">Debugging Tips <a class="header-anchor" href="#debugging-tips" aria-label="Permalink to &quot;Debugging Tips&quot;">​</a></h3><ol><li>Enable detailed logging</li><li>Test basic functions step by step</li><li>Compare with normally working device configurations</li><li>Reference community discussions and issues</li></ol><h2 id="community-support" tabindex="-1">Community Support <a class="header-anchor" href="#community-support" aria-label="Permalink to &quot;Community Support&quot;">​</a></h2><h3 id="project-links" tabindex="-1">Project Links <a class="header-anchor" href="#project-links" aria-label="Permalink to &quot;Project Links&quot;">​</a></h3><ul><li><strong>GitHub Repository</strong>: <a href="https://github.com/c1pher-cn/ha-mcp-for-xiaozhi" target="_blank" rel="noreferrer">ha-mcp-for-xiaozhi</a></li><li><strong>Issue Tracker</strong>: <a href="https://github.com/c1pher-cn/ha-mcp-for-xiaozhi/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li><strong>Feature Requests</strong>: <a href="https://github.com/c1pher-cn/ha-mcp-for-xiaozhi/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></li></ul>`,89)]))}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
